mapper.select:
SELECT w_tme.work_id , p.project_id , t.task_id , u.user_code , w_cls.work_name AS workNameLabel , w_tme.work_date , w_tme.spent_content , w_tme.spent_hour , SUM(w_tme.spent_hour) OVER (ORDER BY w_tme.work_id) AS countSpentHour , SUM(w_tme.spent_hour) OVER () AS totalSpentHour , w_tme.created_at , w_tme.updated_at , p.project_title , u.user_name , t.task_title , t.task_describe , t.estimated_time FROM work_time w_tme LEFT JOIN project P ON w_tme.project_id = p.project_id LEFT JOIN users u ON u.user_code = w_tme.user_code LEFT JOIN work_classification w_cls ON w_tme.work_name = w_cls.task_classification_id LEFT JOIN task t ON t.task_id = w_tme.task_id WHERE w_tme.project_id = #{projectId}
AND w_tme.user_code = #{userCode}
ORDER BY w_tme.work_id DESC

mapper.insert:
INSERT INTO work_time (
                        work_id
                        , project_id
                        , task_id
                        , user_code
                        , work_name
                        , work_date
                        , spent_content
                        , spent_hour
                        , created_at
                        , updated_at
                       )
VALUES (
        ATE_DAY_SEQ.NEXTVAL
        , #{projectId}
        , #{taskId}
        , #{userCode}
        , #{workName}
        , #{workDate}
        , #{spentContent}
        , #{spentHour}
        , SYSDATE
        , SYSDATE
)

mapper.update:
UPDATE task
SET spent_hours_sum = NVL(spent_hours_sum, 0) + #{spentHour}
WHERE task_id = #{taskId}

		UPDATE work_time
		SET    project_id = #{projectId}
       		   , task_id = #{taskId}
       		   , user_code = #{userCode}
       	       , work_name = #{workName}
       		   , work_date = #{workDate}
       		   , spent_content = #{spentContent}
       		   , spent_hour = #{spentHour}
       		   , updated_at = SYSDATE
		WHERE work_id = #{workId}
